INSERT INTO `v1_adc6dc65970917e7aa9574c294fc98f1c3ce2e8172b7bb4f20c7cf1d96bbd332` VALUES ("", 6, "", 11, "あの人にとっては何気ない\n一言だったのかも知れないですけど\n私にはそれがとてもうれしくて", 10, 1060026, 1, 112411, 1, "");
INSERT INTO `v1_adc6dc65970917e7aa9574c294fc98f1c3ce2e8172b7bb4f20c7cf1d96bbd332` VALUES ("", 6, "", 91, "", "", 1060027, "", 0, "", "");
