INSERT INTO `v1_adc6dc65970917e7aa9574c294fc98f1c3ce2e8172b7bb4f20c7cf1d96bbd332` VALUES ("", 7, "", 11, "今思うと…最初のゲリラLIVEは\nほんとうにいっぱいいっぱいでしたね", 10, 1070016, 1, 112411, 1, "");
